import{_ as n}from"./_plugin-vue_export-helper.cdc0426e.js";import{o as s,c as a,f as t}from"./app.5b5c8f59.js";const p={},e=t(`<h2 id="python装饰器" tabindex="-1"><a class="header-anchor" href="#python装饰器" aria-hidden="true">#</a> Python装饰器</h2><p>为什么要用装饰器？ 装饰器用于修改函数的功能，有利于让代码简短并且利于维护。例如我们要给一些函数加上权限检查和日志记录等功能，如果没有装饰器则需要对每一个函数进行修改。如果使用了装饰器，那么我们只需要定义权限检查函数好日志记录函数，然后在需要进行功能增强的函数上加上装饰标识就可以了。 举例：</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">select_data</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
	<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;I am checking permission!&quot;</span><span class="token punctuation">)</span>
	<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Permission allowed!&quot;</span><span class="token punctuation">)</span>
	<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;selecting data!&quot;</span><span class="token punctuation">)</span>
	<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;writing log!&quot;</span><span class="token punctuation">)</span>
<span class="token keyword">def</span> <span class="token function">delete_data</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
	<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;I am checking permission!&quot;</span><span class="token punctuation">)</span>
	<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Permission allowed!&quot;</span><span class="token punctuation">)</span>
	<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;deleting data!&quot;</span><span class="token punctuation">)</span>
	<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;writing log!&quot;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>在这两个函数中出现了大量的重复代码，如果需要进行权限检查和日志写入的函数增多，那么重复代码会更多。</p><div class="language-python line-numbers-mode" data-ext="py"><pre class="language-python"><code><span class="token keyword">def</span> <span class="token function">check_permission</span><span class="token punctuation">(</span>func<span class="token punctuation">)</span><span class="token punctuation">:</span>
	<span class="token decorator annotation punctuation">@wrap</span><span class="token punctuation">(</span>func<span class="token punctuation">)</span>
	<span class="token keyword">def</span> <span class="token function">check</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
		<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;I am checking permission!&quot;</span><span class="token punctuation">)</span>
		<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Permission allowed!&quot;</span><span class="token punctuation">)</span>
		func<span class="token punctuation">(</span><span class="token punctuation">)</span>
		<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;writing log!&quot;</span><span class="token punctuation">)</span>
	<span class="token keyword">return</span> check
<span class="token decorator annotation punctuation">@check_permission</span>
<span class="token keyword">def</span> <span class="token function">select_data</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
	<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;selecting data!&quot;</span><span class="token punctuation">)</span>
<span class="token decorator annotation punctuation">@check_permission</span>
<span class="token keyword">def</span> <span class="token function">delete_data</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">:</span>
	<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;deleting data!&quot;</span><span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>使用装饰器在代码量很大的情况下可以有效减少代码量。其中<code>@wrap(func)</code>是用于修改使用了装饰器函数后的函数指向问题，即使用了装饰器后该函数指向的还是原函数，而非装饰器函数。</p>`,6),o=[e];function c(i,l){return s(),a("div",null,o)}const r=n(p,[["render",c],["__file","py-base-decor.html.vue"]]);export{r as default};
